button_text.script:
function onButtonPress()
	readyToApply = true;
	for i, win in ipairs(window.abilities.getWindows()) do
		if win.statgainroll.getValue() < 1 then
			readyToApply = false;
		end
	end
	if not readyToApply then
		statmsg = window.name.getValue() .. "\r"
		statmsg = statmsg .. "Stat Gain: Can't apply stat gain until all stats have been rolled.\r";
		msgicon = "indicator_stop";
	else							
		statmsg = window.name.getValue() .. "\r"
		statmsg = statmsg .. "Stat Gain Results: \r";
		msgicon = "icon_info";
		for i, win in ipairs(window.abilities.getWindows()) do
			statmsg = statmsg .. win.label.getValue() .. "          ";
			if win.result.getValue() > -1 then
				statmsg = statmsg .. "+";
			end
			statmsg = statmsg .. win.result.getValue() .. "           (" .. win.newtemp.getValue() .. "/" .. win.potential.getValue() .. ")\r";
			win.temp.setValue(win.newtemp.getValue());
			win.statgainroll.setValue(0);
		end
	end
	local msg = {font = "msgfont", icon = msgicon, mode = "system"};
	msg.text = statmsg;
	Comm.deliverChatMessage(msg);
end

function onButtonPress()
	for i, win in ipairs(window.abilities.getWindows()) do
		win.statgainroll.action();
	end
end

windowlist.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						--[[ load the stat list ]]
						local statList = Rules_Stats.List();
						for i = 1, #statList do
							addEntry(statList[i].name, statList[i].label, statList[i].devStat, statList[i].order);
						end
						--[[ force a re-sort ]]
						applySort();
					end

					function addEntry(name, label, dev, order)
						local node = DB.getChild(getDatabaseNode(), name);
						local win;
						if not node then
							node = DB.createChild(getDatabaseNode(), name);
						end
						for i,w in ipairs(getWindows()) do
							if DB.getName(w.getDatabaseNode())==name then
								win = w;
							end
						end
						if win then
							win.label.setValue(label);
							win.order.setValue(order);
						end
					end

					function onSortCompare(w1, w2)
						return (w1.order.getValue() > w2.order.getValue());
					end

number_listitem_right_static_stat_gain_r.script:
					function action(draginfo)
						local charNode = DB.getChild(window.getDatabaseNode(), "...");
						local rActor = ActorManager.resolveActor(charNode);
						ActionStatGain.performRoll(draginfo, rActor, ActionRMDice.D100, window.label.getValue());

						return true;
					end

					function onDragStart(button, x, y, draginfo)
						return action(draginfo);
					end

					function onDoubleClick(x,y)
						return action();
					end
